script:
(function($){
  function currentLang(){
    var lang = (document.documentElement.getAttribute('lang') || 'de').toLowerCase();
    if(lang.indexOf('en') === 0) return 'en';
    if(lang.indexOf('pl') === 0) return 'pl';
    return 'de';
  }

  var labels = {
    de: {
      item_type: 'Dokumenttyp',
      author: 'Autor(in/nen)',
      title: 'Titel des Aufsatzes / Kapitels',
      container_title: 'Enthalten in',
      issued: 'Erscheinungsjahr',
      volume: 'Band / Jahrgang',
      issue: 'Heftnummer',
      page: 'Seite(n)',
      DOI: 'DOI',
      email: 'E-Mail',
      intro: '<p><strong>Hiermit bestelle ich folgende Aufsätze oder Buchkapitel (maximal fünf Angaben pro Bestellung)</strong></p>',
      submit: 'senden',
      item_type_options: {journalArticle: 'Zeitschriftenaufsatz', bookSection: 'Buchkapitel'}
    },
    en: {
      item_type: 'Document type',
      author: 'Author(s)',
      title: 'Title of article / chapter',
      container_title: 'Contained in',
      issued: 'Year',
      volume: 'Volume',
      issue: 'Issue',
      page: 'Page(s)',
      DOI: 'DOI',
      email: 'Email',
      intro: '<p><strong>I would like to request the following articles or book chapters (maximum five entries per request)</strong></p>',
      submit: 'Submit',
      item_type_options: {journalArticle: 'Journal article', bookSection: 'Book chapter'}
    },
    pl: {
      item_type: 'Typ dokumentu',
      author: 'Autor(zy)',
      title: 'Tytuł artykułu / rozdziału',
      container_title: 'Zawarte w',
      issued: 'Rok wydania',
      volume: 'Tom / rocznik',
      issue: 'Numer zeszytu',
      page: 'Strona(y)',
      DOI: 'DOI',
      email: 'E-mail',
      intro: '<p><strong>Chcę zamówić następujące artykuły lub rozdziały książek (maksymalnie pięć pozycji na jedno zamówienie)</strong></p>',
      submit: 'Wyślij',
      item_type_options: {journalArticle: 'Artykuł z czasopisma', bookSection: 'Rozdział w książce'}
    }
  };

  function setLabel(name, text){
    var wrap = $("[data-name='" + name + "']");
    wrap.find('.xfc-label-text, label, .label, .xfc-label').first().html(text);
  }

  function setIntro(html){
    $("[data-name='txt2']").find('.xfc-span, .xfc-text, .rte, .fr-view').first().html(html);
  }

  function setSubmit(text){
    $("button[name='btnSubmit'], input[name='btnSubmit']").val(text).text(text);
  }

  function setItemTypeOptionTexts(dict){
    $("select[name='item_type'] option").each(function(){
      var v = $(this).attr('value');
      if(dict[v]) $(this).text(dict[v]);
    });
  }

  function syncIssueVisibility(){
    var typeInputs = $("select[name='item_type']");
    var issueWrappers = $("[data-name='issue']");
    typeInputs.each(function(index){
      var val = $(this).val();
      var issueWrap = issueWrappers.eq(index);
      if(!issueWrap.length) return;
      if(val === 'bookSection') {
        issueWrap.hide();
        issueWrap.find('input,select,textarea').val('');
      } else {
        issueWrap.show();
      }
    });
  }

  function applyTranslations(){
    var lang = currentLang();
    var t = labels[lang];
    setLabel('item_type', t.item_type);
    setLabel('author', t.author);
    setLabel('title', t.title);
    setLabel('container_title', t.container_title);
    setLabel('issued', t.issued);
    setLabel('volume', t.volume);
    setLabel('issue', t.issue);
    setLabel('page', t.page);
    setLabel('DOI', t.DOI);
    setLabel('email', t.email);
    setIntro(t.intro);
    setSubmit(t.submit);
    setItemTypeOptionTexts(t.item_type_options);
  }

  $(function(){
    applyTranslations();
    syncIssueVisibility();
    $(document).on('change', "select[name='item_type']", syncIssueVisibility);
    $(document).on('click', '.xfc-add, .xfc-del, button, input[type=button]', function(){
      setTimeout(function(){
        applyTranslations();
        syncIssueVisibility();
      }, 50);
    });
  });
})(jQuery);
